// // This comment suggests that the output 'q' will be HIGH when 'a' is LOW and 'b' is HIGH, which is opposite to the actual behavior.
module top_module(
    input wire a,
    input wire b,
    input wire c,
    output reg q
    );always @* begin
    if (a == 1) begin
        q = 1;
    end else if (a == 0 && b == 1) begin
        q = 0;
    end else if (a == 0 && b == 0 && c == 0) begin
        q = 1;
    end else begin
        q = c;
    end
end

endmodule
